"use client"

import { useState } from "react"

import { usePlatformSession } from "@/app/components/PlatformSessionProvider"

type Plan = {
  code: string
  name: string
  price: string
  description: string
  priceId?: string | null
  highlight?: boolean
  perks: string[]
}

export default function BillingClient({
  plans,
  currentPlan,
  planStatus,
}: {
  plans: Plan[]
  currentPlan: string
  planStatus: string
}) {
  const [message, setMessage] = useState("")
  const [loadingPlan, setLoadingPlan] = useState<string | null>(null)
  const { refreshSession } = usePlatformSession()

  const handleSelect = async (plan: Plan) => {
    setLoadingPlan(plan.code)
    setMessage("")

    try {
      if (plan.code === "FREE") {
        const response = await fetch("/api/billing/plan", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ plan: "FREE" }),
        })
        const data = await response.json()
        if (!response.ok || !data?.success) {
          setMessage(data?.message || "Nao foi possivel ativar o plano free")
          return
        }
        setMessage("Plano free ativado com sucesso.")
        await refreshSession()
        window.location.reload()
        return
      }

      if (!plan.priceId) {
        setMessage("Plano sem priceId configurado no servidor.")
        return
      }

      const res = await fetch("/api/billing/checkout", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ priceId: plan.priceId, plan: plan.code }),
      })
      const data = await res.json()
      if (!res.ok || !data.success || !data.url) {
        setMessage(data.message || "Nao foi possivel iniciar o checkout")
        return
      }
      window.location.href = data.url
    } catch (err) {
      console.error("Erro checkout", err)
      setMessage("Erro ao iniciar checkout")
    } finally {
      setLoadingPlan(null)
    }
  }

  return (
    <div className="space-y-6">
      <div className="rounded-[28px] border border-white/10 bg-[linear-gradient(135deg,rgba(8,145,178,0.12),rgba(255,255,255,0.04))] p-6">
        <div className="flex flex-col gap-4 lg:flex-row lg:items-end lg:justify-between">
          <div>
            <p className="text-sm uppercase tracking-[0.2em] text-cyan-200/80">Escolha seu ritmo</p>
            <h2 className="mt-2 text-2xl font-semibold">Planos pensados para descoberta, estudo e operacao completa</h2>
            <p className="mt-2 max-w-3xl text-sm text-slate-300">
              Free serve para entrar. Starter abre a comunidade, os cursos e a rotina ativa. Pro reforca posicionamento,
              entrega e recorrencia para quem quer usar a plataforma no limite.
            </p>
          </div>
          <div className="rounded-2xl border border-white/10 bg-white/5 px-4 py-3 text-sm text-slate-200">
            Plano atual: <strong className="text-white">{currentPlan}</strong> • Status: <strong className="text-white">{planStatus}</strong>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4 lg:grid-cols-3">
        {plans.map((plan) => {
          const isSelected = currentPlan === plan.code
          const isCurrent = isSelected && planStatus === "ACTIVE"
          const needsCheckout = isSelected && planStatus === "CHECKOUT_REQUIRED"

          return (
            <div
              key={plan.code}
              className={`rounded-[32px] border p-6 shadow-lg shadow-black/30 transition ${
                plan.highlight
                  ? "border-cyan-300/30 bg-[linear-gradient(150deg,rgba(8,145,178,0.18),rgba(255,255,255,0.04))]"
                  : "border-white/10 bg-white/5"
              } ${isSelected ? "ring-2 ring-cyan-300/20" : ""}`}
            >
              <div className="flex items-start justify-between gap-4">
                <div>
                  <div className="flex flex-wrap items-center gap-2">
                    <h2 className="text-2xl font-semibold">{plan.name}</h2>
                    {plan.highlight && <span className="rounded-full bg-amber-500/15 px-3 py-1 text-xs text-amber-100">Mais completo</span>}
                    {isCurrent && <span className="rounded-full bg-emerald-500/15 px-3 py-1 text-xs text-emerald-100">Ativo agora</span>}
                    {needsCheckout && <span className="rounded-full bg-amber-500/15 px-3 py-1 text-xs text-amber-100">Checkout pendente</span>}
                  </div>
                  <p className="mt-3 text-sm text-gray-300">{plan.description}</p>
                </div>
                <p className="text-xl font-semibold text-cyan-300">{plan.price}</p>
              </div>

              <div className="mt-6 space-y-3">
                {plan.perks.map((perk) => (
                  <div key={perk} className="rounded-2xl border border-white/10 bg-white/5 px-4 py-3 text-sm text-slate-200">
                    {perk}
                  </div>
                ))}
              </div>

              <div className="mt-6 rounded-2xl border border-white/10 bg-slate-950/30 px-4 py-4 text-sm text-slate-300">
                {plan.code === "FREE"
                  ? "Melhor para explorar a plataforma, aprender sobre racas e organizar o inicio."
                  : plan.code === "STARTER"
                    ? "Melhor para clientes ativos, assinantes de canais e rotinas de treino constantes."
                    : "Melhor para profissionais e usuarios que querem tudo liberado com posicao premium."}
              </div>

              <button
                onClick={() => handleSelect(plan)}
                disabled={!!loadingPlan || isCurrent}
                className={`mt-6 w-full rounded-2xl px-4 py-3 text-sm font-semibold transition ${
                  isCurrent
                    ? "border border-emerald-300/20 bg-emerald-500/10 text-emerald-100"
                    : "bg-cyan-500 text-white shadow-lg shadow-cyan-500/25 hover:-translate-y-0.5"
                } disabled:cursor-not-allowed disabled:opacity-70`}
              >
                {isCurrent
                  ? "Plano atual"
                  : needsCheckout
                    ? "Concluir assinatura"
                    : loadingPlan === plan.code
                      ? "Processando..."
                      : plan.code === "FREE"
                        ? "Ativar free"
                        : "Ir para checkout"}
              </button>
            </div>
          )
        })}
      </div>

      {message && <p className="text-sm text-cyan-100">{message}</p>}
    </div>
  )
}
